<template>
	<view class="set_api_page">
		<view class="tip">
			<u-parse :html="tip"></u-parse>
		</view>
		<u-form :model="ruleForm" label-position="top" ref="uForm" :rules="rules" label-width="130">


			<u-form-item label="商品通知地址" prop="goods_notify_url"><u-input v-model.trim="ruleForm.goods_notify_url"
					clearable placeholder="通知对接商品状态和价格变动" />
				<u-button type="primary" @click="handelCopy(ruleForm.goods_notify_url)" size="mini">复制</u-button>
			</u-form-item>
			<u-form-item label="白名单IP" prop="income_ip"><u-input v-model.trim="ruleForm.income_ip" type="textarea"
					:rows="6" clearable placeholder="" :disabled="!incomeOrder" />
				<u-button type="primary" @click="handelCopy(ruleForm.income_ip)" size="mini">复制</u-button>
			</u-form-item>
			<u-form-item label="验证方式" prop="code_type" v-if="incomeOrder && codeTypeList.length>0">
				<u-input v-model.trim="codeTypeText" :clearable="false" placeholder="" @click="showCodeType = true"
					:custom-style="{color: '#999'}" />
				<u-select v-model="showCodeType" :list="codeTypeList" :default-value="codeTypeDefaultValue"
					@confirm="confirm"></u-select>
				<u-button type="primary" @click="$util.on('/pages/ucenter_sub/set')" size="mini"
					v-show="isError">去设置</u-button>
			</u-form-item>
			<u-form-item label="" label-width="0" v-if="incomeOrder">
				<u-button type="primary" style="display: block;width: 40%;" @click="submitForm('uForm',1)">保存</u-button>
				<u-button type="primary" style="display: block;width: 40%;"
					@click="submitForm('uForm',2)">重置密钥</u-button>
			</u-form-item>
		</u-form>
		<u-popup v-model="showKey" class="addbank" width="686" mode="center" :z-index="6"
			:custom-style="{marginBottom:'100rpx'}" :mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}"
			:border-radius="20">
			<view class="popup-content">
				<u-form :model="ruleForm" label-width="130" label-position="top">
					<u-form-item label="APPID" prop="income_app"><u-input v-model.trim="ruleForm.income_app" clearable
							placeholder="" disabled />
						<view style="margin-left: 20rpx;" v-if="incomeOrder">
							<template v-if="ruleForm.income_app">
								<u-button type="primary" @click="handelCopy(ruleForm.income_app)"
									size="mini">复制</u-button>

							</template>

						</view>

					</u-form-item>
					<u-form-item label="密钥" prop="income_key"><u-input v-model.trim="ruleForm.income_key" clearable
							placeholder="" disabled />
						<view style="margin-left: 20rpx;" v-if="incomeOrder">
							<template v-if="ruleForm.income_key">
								<u-button type="primary" @click="handelCopy(ruleForm.income_key)"
									size="mini">复制</u-button>

							</template>

						</view>

					</u-form-item>
				</u-form>
				<view class="btns">
					<u-button @click="showKey = false" class="submit-btn">关闭</u-button>
				</view>
			</view>
		</u-popup>
		<mobile-code-input :popupShow.sync="showMobileCodeInput" @ok="handelMobileCodeInputOk" />
		<email-code-input :popupShow.sync="showEmailCodeInput" @ok="handelEmailCodeInputOk" />
		<password-input :popupShow.sync="showPassInput" @ok="handelInputOk" />
	</view>
</template>

<script>
	import MobileCodeInput from './components/mobile-code-input/index'
	import EmailCodeInput from './components/email-code-input/index'
	import PasswordInput from '@/components/password-input/index'

	import {
		randomString
	} from '@/common/fun.js'
	
	export default {
		components: {
			'mobile-code-input': MobileCodeInput,
			'email-code-input': EmailCodeInput,
			'password-input': PasswordInput,
		},
		data() {
			const CodeTypeValidator = (rule, value, callback) => {
				const code_type = this.ruleForm.code_type
				if (code_type == 'sms' && !this.userinfo.mobile) {
					this.isError = true
					callback('未绑定手机号码')
				} else if (code_type == 'email' && !this.userinfo.email) {
					this.isError = true
					callback('未绑定邮箱')
				} else if (code_type == 'trade_password' && !this.userinfo.has_trade_password) {
					this.isError = true
					callback('未设置交易密码')
				} else {
					this.isError = false
					callback()
				}
			}
			return {
				tip: '',
				ruleForm: {
					id: '',
					income_ip: '',
					income_key: '',
					code_type: '',
					mobile_code: '',
					email_code: '',
					trade_password: '',
					goods_notify_url: '',
				},
				rules: {
					// income_key: [{
					// 	required: true,
					// 	message: '请输入接口密钥',
					// 	trigger: ['blur', 'change']
					// }],
					code_type: [{
						required: true,
						message: '请选择验证方式',
						trigger: ['blur', 'change']
					}, {
						validator: CodeTypeValidator
					}],
				},
				isError: false,
				showCodeType: false,
				openSafeApiVerify: [],
				incomeOrder: false,

				checkType: 1, //1保存2重置密钥
				showKey: false, //显示密钥

				showMobileCodeInput: false,
				showEmailCodeInput: false,
				showPassInput: false,
			};
		},
		computed: {
			codeTypeList() {
				const arr = [{
					label: '短信验证',
					value: 'sms'
				}, {
					label: '邮箱验证',
					value: 'email'
				}, {
					label: '交易密码',
					value: 'trade_password'
				}].filter(item => {
					if (this.openSafeApiVerify.includes(item.value))
						return item
				})
				return arr
			},
			codeTypeDefaultValue() {
				if (this.ruleForm.code_type) {
					return [this.codeTypeList.findIndex(item => item.value == this.ruleForm.code_type)]
				} else
					return []
			},
			codeTypeText() {
				const item = this.codeTypeList.find(item => item.value == this.ruleForm.code_type)
				if (item)
					return item.label
				else
					return '请选择验证方式'
			},
		},
		onLoad() {
			this.fetchData()

		},
		methods: {
			async fetchData(type) {
				const {
					id,
					income_app,
					income_key,
					// read_income_key,
					income_ip,
					tip,
					open_safe_api_verify,
					income_order,
					goods_notify_url,
				} = await this.$u.api.incomeConfig()
				this.ruleForm.id = id
				this.ruleForm.income_ip = income_ip
				this.ruleForm.income_app = income_app
				this.ruleForm.income_key = income_key
				this.ruleForm.goods_notify_url = goods_notify_url
				this.tip = tip
				this.openSafeApiVerify = open_safe_api_verify
				this.incomeOrder = income_order
				if (this.codeTypeList.length > 0 && !this.ruleForm.code_type) {
					this.ruleForm.code_type = open_safe_api_verify[0]
				}

			},
			handelCopy(val) {
				uni.setClipboardData({
					data: val,
					success: function() {
						uni.showToast({
							title: '复制成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					}
				})
			},
			confirm(e) {
				const {
					label,
					value
				} = [...e].pop()
				this.ruleForm.code_type = value
			},
			createKey() {



				this.ruleForm.income_key = randomString()
			},
			resetForm(formName) {
				this.$refs[formName].resetFields()
			},
			submitForm(formName, type) {
				this.checkType = type
				this.$refs[formName].setRules(this.rules)
				this.$refs[formName].validate(async (valid) => {
					if (valid) {
						if (this.codeTypeList.length > 0) {
							if (this.ruleForm.code_type == 'sms') {
								this.showMobileCodeInput = true
							} else if (this.ruleForm.code_type == 'email') {
								this.showEmailCodeInput = true
							} else if (this.ruleForm.code_type == 'trade_password') {
								this.showPassInput = true
							}




						} else {
							if (this.checkType == 2) {
								this.toReq()
							} else {
								await this.$u.api.incomeSave(this.ruleForm)
								this.$u.toast('保存成功')
							}

						}
					} else {
						console.log('error submit!!')
						return false
					}
				})
			},
			async handelMobileCodeInputOk(e) {
				this.ruleForm.mobile_code = e
				await this.toReq()

			},
			async handelEmailCodeInputOk(e) {
				this.ruleForm.email_code = e
				await this.toReq()


			},
			async handelInputOk(e) {
				this.ruleForm.trade_password = e
				await this.toReq()


			},
			//请求保存
			async toReq() {
				if (this.checkType == 2) {
					const {
						income_app,
						income_key,
					} = await this.$u.api.resetIncomeKey(this.ruleForm)

					this.ruleForm.income_app = income_app
					this.ruleForm.income_key = income_key
					this.showKey = true
				} else {
					await this.$u.api.incomeSave(this.ruleForm)
					this.$u.toast('保存成功')
				}
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	.set_api_page {
		padding: 20rpx;
		background-color: #fff;

		.tip {
			background-color: #dbf1e1;
			padding: 12rpx 24rpx;
			border-radius: 6rpx;
			position: relative;
			transition: all .3s linear;
			border: 1px solid #71d5a1;
		}
	}

	/deep/ .addbank .u-mode-center-box {
		padding: 20rpx;
	}
</style>